{
  "type": "DRAG_FILL",
  "lessonText": "Engage in a fun challenge to learn important facts about sex education.",
  "data": {
    "challenges": [
      {
        "instruction": "Fill in the blanks with the correct terms.",
        "codeTemplate": "Sexual health includes ___, ___, and ___ education.",
        "options": ["emotional", "physical", "social"],
        "correctAnswer": "emotional,physical,social",
        "explanation": "Sexual health encompasses emotional, physical, and social aspects."
      },
      {
        "instruction": "Complete the statement with the right words.",
        "codeTemplate": "Consent means ___, ___, and ___ agreement.",
        "options": ["clear", "enthusiastic", "ongoing"],
        "correctAnswer": "clear,enthusiastic,ongoing",
        "explanation": "Consent must be clear, enthusiastic, and ongoing."
      },
      {
        "instruction": "Identify the key components of safe sex.",
        "codeTemplate": "Safe sex practices include ___, ___, and ___ methods.",
        "options": ["condoms", "communication", "testing"],
        "correctAnswer": "condoms,communication,testing",
        "explanation": "Condoms, communication, and testing are essential for safe sex."
      },
      {
        "instruction": "Fill in the blanks about puberty.",
        "codeTemplate": "Puberty involves ___, ___, and ___ changes.",
        "options": ["physical", "emotional", "social"],
        "correctAnswer": "physical,emotional,social",
        "explanation": "Puberty includes physical, emotional, and social changes."
      }
    ]
  }
}
